public static void main(Args args)
{
    var builder = DBMSQLQueryStorePlanViewBuilder::construct();
    builder.createSqlObjects();
}

private str createViewSqlStmt()
{
    str sqlStmt = 'CREATE VIEW ' + viewName + ' AS ' + this.createSQLStatement();
    return sqlStmt;
}

private str createSQLStatement()
{
    if (DBMSQLUtils::databaseCompatibilityLevel() >= 160)
    {
        return this.createSQLStatement2022();
    }
    else
    {
        return this.createSQLStatement2019();
    }
}

protected void initialize(boolean _runOnSeparateUserConnection = false)
{
    super(_runOnSeparateUserConnection);

    SysDictView view    = new SysDictView(tableNum(DBMSQLQueryStorePlan));
    viewName            = view.name(DbBackend::Sql);
    asPlanId = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, PlanId)).name(DbBackend::Sql);
    asQueryId = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, QueryId)).name(DbBackend::Sql);
    asPlanGroupId = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, PlanGroupId)).name(DbBackend::Sql);
    asEngineVersion = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, EngineVersion)).name(DbBackend::Sql);
    asCompatibilityLevel = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, CompatibilityLevel)).name(DbBackend::Sql);
    asQueryPlanHash = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, QueryPlanHash)).name(DbBackend::Sql);
    asQueryPlan = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, QueryPlan)).name(DbBackend::Sql);
    asIsOnlineIndexPlan = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, IsOnlineIndexPlan)).name(DbBackend::Sql);
    asIsTrivialPlan = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, IsTrivialPlan)).name(DbBackend::Sql);
    asIsParallelPlan = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, IsParallelPlan)).name(DbBackend::Sql);
    asIsForcedPlan = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, IsForcedPlan)).name(DbBackend::Sql);
    asIsNativelyCompiled = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, IsNativelyCompiled)).name(DbBackend::Sql);
    asForceFailureCount = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, ForceFailureCount)).name(DbBackend::Sql);
    asLastForceFailureReason = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, LastForceFailureReason)).name(DbBackend::Sql);
    asLastForceFailureReasonDesc = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, LastForceFailureReasonDesc)).name(DbBackend::Sql);
    asCountCompiles = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, CountCompiles)).name(DbBackend::Sql);
    asInitialCompileStartTime = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, InitialCompileStartTime)).name(DbBackend::Sql);
    asLastCompileStartTime = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, LastCompileStartTime)).name(DbBackend::Sql);
    asLastExecutionTime = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, LastExecutionTime)).name(DbBackend::Sql);
    asAvgCompileDuration = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, AvgCompileDuration)).name(DbBackend::Sql);
    asLastCompileDuration = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, LastCompileDuration)).name(DbBackend::Sql);
    asPlanForcingType = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, PlanForcingType)).name(DbBackend::Sql);
    asPlanForcingTypeDesc = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, PlanForcingTypeDesc)).name(DbBackend::Sql);
    asHasCompileReplayScript = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, HasCompileReplayScript)).name(DbBackend::Sql);
    asIsOptimizedPlanForcingDisabled = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, IsOptimizedPlanForcingDisabled)).name(DbBackend::Sql);
    asPlanType = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, PlanType)).name(DbBackend::Sql);
    asPlanTypeDesc = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, PlanTypeDesc)).name(DbBackend::Sql);
    asRecId = view.fieldObject(fieldNum(DBMSQLQueryStorePlan, RecId)).name(DbBackend::Sql);

}

public static DBMSQLQueryStorePlanViewBuilder construct()
{
    return new DBMSQLQueryStorePlanViewBuilder();
}
